div.script:
function clearPad(canvasId) {
    var canvas = document.getElementById(canvasId);
    if (!canvas) return;
    var ctx = canvas.getContext('2d');
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    var inputId = '';
    if (canvasId === 'employee-pad') inputId = 'employee_sig_data';
    else if (canvasId === 'manager-pad') inputId = 'manager_sig_data';
    else if (canvasId === 'witness-pad') inputId = 'witness_sig_data';

    var input = document.getElementById(inputId);
    if (input) input.value = '';
}

function psmShowValidationModal(errors) {
    var list = document.getElementById('psm_validation_error_list');
    if (!list) return;
    list.innerHTML = '';
    errors.forEach(function(msg) {
        var li = document.createElement('li');
        li.style.cssText = 'display:flex;align-items:flex-start;gap:10px;' +
                           'background:#FFF8E1;border-left:4px solid #FFC72C;' +
                           'border-radius:6px;padding:10px 14px;';
        li.innerHTML = '<i class="fa fa-exclamation-triangle mt-1" ' +
                       'style="color:#FFC72C;flex-shrink:0;"></i>' +
                       '<span style="color:#000000;font-weight:500;">' + msg + '</span>';
        list.appendChild(li);
    });

    var modalEl = document.getElementById('psm_validation_modal');
    var bsApi = window.bootstrap || (window.odoo && window.odoo.bootstrap) || null;
    if (modalEl && bsApi && bsApi.Modal) {
        bsApi.Modal.getOrCreateInstance(modalEl).show();
    } else if (modalEl) {
        modalEl.style.display = 'block';
        modalEl.classList.add('show');
        document.body.classList.add('modal-open');
        document.body.style.overflow = 'hidden';
        modalEl.querySelectorAll('[data-bs-dismiss="modal"]').forEach(function(btn) {
            btn.addEventListener('click', function() {
                modalEl.classList.remove('show');
                modalEl.style.display = 'none';
                document.body.classList.remove('modal-open');
                document.body.style.overflow = '';
            });
        });
    }
}

document.addEventListener('DOMContentLoaded', function() {
    var empSelect = document.getElementById('employee_select');
    var deptDisplay = document.getElementById('emp_dept_display');
    var jobDisplay = document.getElementById('emp_job_display');
    var nameDisplay = document.getElementById('emp_name_display');
    var barcodeDisplay = document.getElementById('emp_barcode_display');

    if (empSelect) {
        empSelect.addEventListener('change', function() {
            var selectedOption = empSelect.options[empSelect.selectedIndex];
            if (selectedOption && selectedOption.value) {
                nameDisplay.textContent = selectedOption.textContent.split('(')[0].trim() || '---';
                barcodeDisplay.textContent = selectedOption.getAttribute('data-empid') || '---';
                deptDisplay.textContent = selectedOption.getAttribute('data-dept') || '---';
                jobDisplay.textContent = selectedOption.getAttribute('data-job') || '---';
            } else {
                nameDisplay.textContent = '---';
                barcodeDisplay.textContent = '---';
                deptDisplay.textContent = '---';
                jobDisplay.textContent = '---';
            }
        });
    }

    // Witness Logic
    var witnessSelect = document.getElementById('witness_select');
    var witnessDeptDisplay = document.getElementById('witness_dept_display');
    var witnessNameDisplay = document.getElementById('witness_name_display');
    var witnessIdDisplay = document.getElementById('witness_id_display');
    var witnessJobDisplay = document.getElementById('witness_job_display');
    var witnessSigRow = document.getElementById('witness_signature_row');


    if (witnessSelect) {
        witnessSelect.addEventListener('change', function() {
            var selectedOption = witnessSelect.options[witnessSelect.selectedIndex];
            if (selectedOption && selectedOption.value) {
                witnessNameDisplay.textContent = selectedOption.textContent.split('(')[0].trim() || '---';
                witnessIdDisplay.textContent = selectedOption.getAttribute('data-empid') || '---';
                witnessDeptDisplay.textContent = selectedOption.getAttribute('data-dept') || '---';
                witnessJobDisplay.textContent = selectedOption.getAttribute('data-job') || '---';
                witnessSigRow.classList.remove('d-none');
                // Re-initialize witness pad size after showing it
                setTimeout(function() {
                    var canvas = document.getElementById('witness-pad');
                    if (canvas) {
                        var rect = canvas.getBoundingClientRect();
                        canvas.width = rect.width;
                        canvas.height = 160;
                        var ctx = canvas.getContext('2d');
                        ctx.strokeStyle = '#2c3e50';
                        ctx.lineWidth = 3;
                        ctx.lineCap = 'round';
                    }
                }, 100);
            } else {
                witnessNameDisplay.textContent = '---';
                witnessIdDisplay.textContent = '---';
                witnessDeptDisplay.textContent = '---';
                witnessJobDisplay.textContent = '---';
                witnessSigRow.classList.add('d-none');
                clearPad('witness-pad');
            }
        });
    }

    // Image Preview Logic
    var imageInput = document.getElementById('explanation_images_input');
    var previewContainer = document.getElementById('image_preview_container');

    if (imageInput && previewContainer) {
        imageInput.addEventListener('change', function() {
            previewContainer.innerHTML = '';
            if (this.files) {
                Array.from(this.files).forEach(file => {
                    if (!file.type.startsWith('image/')) return;

                    var reader = new FileReader();
                    reader.onload = function(e) {
                        var div = document.createElement('div');
                        div.className = 'position-relative border rounded p-1 bg-white shadow-sm';
                        div.style.width = '120px';

                        var img = document.createElement('img');
                        img.src = e.target.result;
                        img.className = 'img-thumbnail border-0';
                        img.style.width = '110px';
                        img.style.height = '110px';
                        img.style.objectFit = 'cover';

                        div.appendChild(img);
                        previewContainer.appendChild(div);
                    }
                    reader.readAsDataURL(file);
                });
            }
        });
    }

    // Signature Pads Initialization
    var pads = document.querySelectorAll('.signature-pad');
    pads.forEach(function(canvas) {
        var ctx = canvas.getContext('2d');
        var drawing = false;
        var lastX, lastY;

        function resize() {
            var rect = canvas.getBoundingClientRect();
            canvas.width = rect.width;
            canvas.height = 160;
            ctx.strokeStyle = '#2c3e50';
            ctx.lineWidth = 3;
            ctx.lineCap = 'round';
        }
        resize();

        function getPos(e) {
            var rect = canvas.getBoundingClientRect();
            var pos = e.touches ? e.touches[0] : e;
            return { x: pos.clientX - rect.left, y: pos.clientY - rect.top };
        }

        canvas.addEventListener('mousedown', function(e) { drawing = true; var pos = getPos(e); lastX = pos.x; lastY = pos.y; });
        canvas.addEventListener('mousemove', function(e) {
            if (!drawing) return; e.preventDefault();
            var pos = getPos(e); ctx.beginPath(); ctx.moveTo(lastX, lastY); ctx.lineTo(pos.x, pos.y); ctx.stroke();
            lastX = pos.x; lastY = pos.y; updateData();
        });
        window.addEventListener('mouseup', function() { drawing = false; });

        canvas.addEventListener('touchstart', function(e) { drawing = true; var pos = getPos(e); lastX = pos.x; lastY = pos.y; });
        canvas.addEventListener('touchmove', function(e) { if (!drawing) return; e.preventDefault(); var pos = getPos(e); ctx.beginPath(); ctx.moveTo(lastX, lastY); ctx.lineTo(pos.x, pos.y); ctx.stroke(); lastX = pos.x; lastY = pos.y; updateData(); });
        window.addEventListener('touchend', function() { drawing = false; });

        function updateData() {
            var dataUrl = canvas.toDataURL('image/png');
            var inputId = '';
            if (canvas.id === 'employee-pad') inputId = 'employee_sig_data';
            else if (canvas.id === 'manager-pad') inputId = 'manager_sig_data';
            else if (canvas.id === 'witness-pad') inputId = 'witness_sig_data';

            var input = document.getElementById(inputId);
            if (input) input.value = dataUrl.split(',')[1];
        }
    });

    // Form Submission Validation
    var form = document.getElementById('discipline_create_form');
    if (form) {
        form.addEventListener('submit', function(e) {
            var managerSig = document.getElementById('manager_sig_data').value;
            var employeeSig = document.getElementById('employee_sig_data').value;
            var images = document.getElementById('explanation_images_input').files;

            var errors = [];
            if (!managerSig || managerSig.length < 500) errors.push("Vui lòng ký tên Quản lý.");
            if (!employeeSig || employeeSig.length < 500) errors.push("Vui lòng ký tên Nhân viên.");
            if (images.length === 0) errors.push("Vui lòng tải lên ít nhất 1 ảnh bản tường trình.");

            if (errors.length > 0) {
                e.preventDefault();
                psmShowValidationModal(errors);
            }
        });
    }
});

if (typeof clearPad !== 'function') {
    window.clearPad = function(canvasId) {
        var canvas = document.getElementById(canvasId);
        if (!canvas) return;
        var ctx = canvas.getContext('2d');
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        var inputId = '';
        if (canvasId === 'employee-pad') inputId = 'employee_sig_data';
        else if (canvasId === 'manager-pad') inputId = 'manager_sig_data';
        else if (canvasId === 'witness-pad') inputId = 'witness_sig_data';

        var input = document.getElementById(inputId);
        if (input) input.value = '';
    };
}

function psmShowValidationModal(errors) {
    var list = document.getElementById('psm_validation_error_list');
    if (!list) return;
    list.innerHTML = '';
    errors.forEach(function(msg) {
        var li = document.createElement('li');
        li.style.cssText = 'display:flex;align-items:flex-start;gap:10px;' +
                           'background:#FFF8E1;border-left:4px solid #FFC72C;' +
                           'border-radius:6px;padding:10px 14px;';
        li.innerHTML = '<i class="fa fa-exclamation-triangle mt-1" ' +
                       'style="color:#FFC72C;flex-shrink:0;"></i>' +
                       '<span style="color:#000000;font-weight:500;">' + msg + '</span>';
        list.appendChild(li);
    });

    var modalEl = document.getElementById('psm_validation_modal');
    var bsApi = window.bootstrap || (window.odoo && window.odoo.bootstrap) || null;
    if (modalEl && bsApi && bsApi.Modal) {
        bsApi.Modal.getOrCreateInstance(modalEl).show();
    } else if (modalEl) {
        modalEl.style.display = 'block';
        modalEl.classList.add('show');
        document.body.classList.add('modal-open');
        document.body.style.overflow = 'hidden';
        modalEl.querySelectorAll('[data-bs-dismiss="modal"]').forEach(function(btn) {
            btn.addEventListener('click', function() {
                modalEl.classList.remove('show');
                modalEl.style.display = 'none';
                document.body.classList.remove('modal-open');
                document.body.style.overflow = '';
            });
        });
    }
}

document.addEventListener('DOMContentLoaded', function() {
    var pads = document.querySelectorAll('.signature-pad');
    pads.forEach(function(canvas) {
        var ctx = canvas.getContext('2d');
        var drawing = false;
        var lastX, lastY;

        function resize() {
            var rect = canvas.getBoundingClientRect();
            canvas.width = rect.width;
            canvas.height = canvas.getAttribute('id') === 'witness-pad' ? 160 : 200;
            ctx.strokeStyle = '#2c3e50';
            ctx.lineWidth = 4;
            ctx.lineCap = 'round';
        }
        resize();

        function getPos(e) {
            var rect = canvas.getBoundingClientRect();
            var pos = e.touches ? e.touches[0] : e;
            return { x: pos.clientX - rect.left, y: pos.clientY - rect.top };
        }

        canvas.addEventListener('mousedown', function(e) { drawing = true; var pos = getPos(e); lastX = pos.x; lastY = pos.y; });
        canvas.addEventListener('mousemove', function(e) {
            if (!drawing) return; e.preventDefault();
            var pos = getPos(e); ctx.beginPath(); ctx.moveTo(lastX, lastY); ctx.lineTo(pos.x, pos.y); ctx.stroke();
            lastX = pos.x; lastY = pos.y; updateData();
        });
        window.addEventListener('mouseup', function() { drawing = false; });

        canvas.addEventListener('touchstart', function(e) { drawing = true; var pos = getPos(e); lastX = pos.x; lastY = pos.y; });
        canvas.addEventListener('touchmove', function(e) { if (!drawing) return; e.preventDefault(); var pos = getPos(e); ctx.beginPath(); ctx.moveTo(lastX, lastY); ctx.lineTo(pos.x, pos.y); ctx.stroke(); lastX = pos.x; lastY = pos.y; updateData(); });
        window.addEventListener('touchend', function() { drawing = false; });

        function updateData() {
            var dataUrl = canvas.toDataURL('image/png');
            var inputId = '';
            if (canvas.id === 'employee-pad') inputId = 'employee_sig_data';
            else if (canvas.id === 'manager-pad') inputId = 'manager_sig_data';
            else if (canvas.id === 'witness-pad') inputId = 'witness_sig_data';

            var input = document.getElementById(inputId);
            if (input) input.value = dataUrl.split(',')[1];
        }
    });

    function requireSignature(formId, inputId, message, contentFieldName, contentMessage) {
        var form = document.getElementById(formId);
        var input = document.getElementById(inputId);
        if (!form || !input) return;
        form.addEventListener('submit', function(ev) {
            var errors = [];
            if (contentFieldName) {
                var content = form.querySelector('[name="' + contentFieldName + '"]');
                if (!content || !content.value || !content.value.trim()) {
                    errors.push(contentMessage);
                }
            }
            if (!input.value || input.value.length < 500) {
                errors.push(message);
            }
            if (errors.length > 0) {
                ev.preventDefault();
                psmShowValidationModal(errors);
            }
        });
    }

    requireSignature(
        'employee_sig_form',
        'employee_sig_data',
        'Vui lòng ký tên Nhân viên trước khi gửi.',
        'section_ii_feedback',
        'Vui lòng nhập nội dung phản hồi của Nhân viên.'
    );
    requireSignature(
        'manager_sig_form',
        'manager_sig_data',
        'Vui lòng ký tên Quản lý trước khi hoàn tất.'
    );
    var responseForm = document.getElementById('employee_response_form');
    if (responseForm) {
        responseForm.addEventListener('submit', function(ev) {
            var submitter = ev.submitter || document.activeElement;
            if (submitter && submitter.value === 'reject') {
                var note = document.getElementById('employee_reject_note');
                if (!note || !note.value || !note.value.trim()) {
                    ev.preventDefault();
                    psmShowValidationModal(['Vui lòng nhập lý do từ chối trước khi gửi.']);
                }
            }
        });
    }
});
